import { useState } from 'react';

function Home() {
	const [gameName, setGameName] = useState('');
	const [playerName, setPlayerName] = useState('');

	return (
		<>
		<h1 class="font-caesar flex text-[120px]">
			RED-TETRIS
		</h1>
		<div class="w-full h-full">
			<input class="" maxLength="10" placeholder="Entrer a name for create the game room" value={gameName} onChange={(e) => setGameName(e.target.value)} />
			<input class="" maxLength="10" placeholder="Entrer a name" value={playerName} onChange={(e) => setPlayerName(e.target.value)} />
			<button onClick={() => (window.location.href = `/${gameName}/${playerName}`)}> Creer </button>
		</div>
		</>
	);
}

export default Home;
